hooks.command:
bash -c '
CHANGED=$(git diff --cached --name-only 2>/dev/null);
if echo "$CHANGED" | grep -qE "\.(sql|py)$" && ! echo "$CHANGED" | grep -q "schema.sql"; then
  echo "\n⚠️  WARNING: SQL/Python files staged but sql/schema.sql NOT staged.";
  echo "Run /schema-change workflow before committing DB changes.";
fi;
git push 2>&1 && echo "✅ Pushed to $(git branch --show-current)" || echo "⚠️  Push failed — check remote"
'
